// HasCharacters applies the HasEdge predicate on the "characters" edge.
func HasCharacters() predicate.Ability {
	return predicate.Ability(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, CharactersTable, CharactersColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasCharactersWith applies the HasEdge predicate on the "characters" edge with a given conditions (other predicates).
func HasCharactersWith(preds ...predicate.Character) predicate.Ability {
	return predicate.Ability(func(s *sql.Selector) {
		step := newCharactersStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Ability) predicate.Ability {
	return predicate.Ability(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Ability) predicate.Ability {
	return predicate.Ability(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Ability) predicate.Ability {
	return predicate.Ability(sql.NotPredicates(p))
}
